from __future__ import annotations
import base64
import zlib
from pathlib import Path

ROOT = Path(__file__).resolve().parents[2]
PATCH_MARKER = "batch55c-hotfixes-admin-polish-corrections"

FILES = [
    ('frontend/admin/assets/js/admin-auth.js', ''),
    ('frontend/admin/assets/js/admin-catalog.js', ''),
    ('frontend/admin/assets/js/admin-cms.js', ''),
    ('frontend/admin/assets/js/admin-dashboard.js', ''),
    ('frontend/admin/assets/js/admin-leads.js', ''),
    ('frontend/admin/assets/css/admin.css', ''),
    ('frontend/admin/assets/css/admin-media.css', ''),
    ('frontend/admin/index.html', ''),
    ('frontend/admin/login.html', ''),
    ('frontend/admin/products.html', ''),
    ('frontend/admin/categories.html', ''),
    ('frontend/admin/brands.html', ''),
    ('frontend/admin/key-features.html', ''),
    ('frontend/admin/customers.html', ''),
    ('frontend/admin/bookings.html', ''),
    ('frontend/admin/inquiries.html', ''),
    ('frontend/admin/about.html', ''),
    ('frontend/admin/project-gallery.html', ''),
    ('frontend/admin/services.html', ''),
    ('frontend/admin/contact-us.html', ''),

]


def write_file(rel_path: str, payload: str) -> None:
    target = ROOT / rel_path
    target.parent.mkdir(parents=True, exist_ok=True)
    data = zlib.decompress(base64.b64decode(payload.encode("ascii")))
    target.write_bytes(data)
    print(f"[ok] Wrote {rel_path}")


def main() -> None:
    for rel_path, payload in FILES:
        write_file(rel_path, payload)
    print("[done] Batch 55C-Hotfixes admin polish corrections applied.")
    print("[note] No DynamoDB tables were deleted, no counters were reset, and no S3/upload storage was enabled.")
    print("[verify] Run node --check on admin JS files and marker Select-String commands from the README before committing.")


if __name__ == "__main__":
    main()
